1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string }[] }): number {
12	  if (input.items.length === 0) return PROCESSING_FEE;
13	  const basePremium = BASE_PREMIUM_BY_TYPE[input.items[0].type];
14	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
15	  return basePremium + firstInsurance + PROCESSING_FEE;
16	}
